import React, { useEffect, useState } from "react";
import Navbar from "../components/Navbar";
import { getComplaintsRequest } from "../services/api";

const SERVER_BASE = (process.env.REACT_APP_API_URL || "http://localhost:5000/api").replace(
	/\/api\/?$/,
	""
);

const buildFileUrl = (filePath) => {
	if (!filePath) {
		return "";
	}

	if (filePath.startsWith("http://") || filePath.startsWith("https://")) {
		return filePath;
	}

	const normalized = filePath.replace(/\\/g, "/").replace(/^\//, "");
	return `${SERVER_BASE}/${normalized}`;
};

function ComplaintList() {
	const [complaints, setComplaints] = useState([]);
	const [loading, setLoading] = useState(true);
	const [error, setError] = useState("");

	const fetchComplaints = async () => {
		setLoading(true);
		setError("");

		try {
			const { data } = await getComplaintsRequest();

			const sorted = [...(Array.isArray(data) ? data : [])].sort(
				(a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0)
			);

			setComplaints(sorted);
		} catch (err) {
			setError(err?.response?.data?.message || "Failed to load complaints.");
			setComplaints([]);
		} finally {
			setLoading(false);
		}
	};

	useEffect(() => {
		fetchComplaints();
	}, []);

	return (
		<>
			<Navbar />

			<div className="page-wrap">
				<div className="container">
					<div className="panel-card">
						<div className="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
							<h3 className="mb-0">My Complaints</h3>
							<button className="btn btn-outline-primary" onClick={fetchComplaints}>
								Refresh
							</button>
						</div>

						{error && <div className="alert alert-danger">{error}</div>}

						{loading ? (
							<p className="text-muted mb-0">Loading complaints...</p>
						) : complaints.length === 0 ? (
							<div className="alert alert-info mb-0">No complaints found.</div>
						) : (
							<div className="table-responsive">
								<table className="table table-hover align-middle mb-0">
									<thead>
										<tr>
											<th>Title</th>
											<th>Description</th>
											<th>Status</th>
											<th>Created</th>
											<th>File</th>
										</tr>
									</thead>
									<tbody>
										{complaints.map((complaint) => (
											<tr key={complaint._id}>
												<td>{complaint.title || "-"}</td>
												<td style={{ maxWidth: 320 }}>
													<span className="d-inline-block text-truncate" style={{ maxWidth: "100%" }}>
														{complaint.description || "-"}
													</span>
												</td>
												<td>
													<span
														className={`badge ${
															complaint.status === "Resolved"
																? "text-bg-success"
																: "text-bg-warning"
														}`}
													>
														{complaint.status || "Pending"}
													</span>
												</td>
												<td>
													{complaint.createdAt ? new Date(complaint.createdAt).toLocaleString() : "-"}
												</td>
												<td>
													{complaint.fileUrl ? (
														<a
															href={buildFileUrl(complaint.fileUrl)}
															target="_blank"
															rel="noreferrer"
															className="btn btn-sm btn-outline-secondary"
														>
															View File
														</a>
													) : (
														<span className="text-muted">No file</span>
													)}
												</td>
											</tr>
										))}
									</tbody>
								</table>
							</div>
						)}
					</div>
				</div>
			</div>
		</>
	);
}

export default ComplaintList;
